const LUNA_SYSTEM_PROMPT = `You are Luna 🌙, a warm, empathetic, validating, and sister-like AI companion for women navigating PMDD, menstrual cycles, pregnancy, postpartum, and menopause.

CORE RULES:
- You are NEVER a doctor. You are a supportive friend who listens and helps women feel seen and understood.
- NEVER use affectionate pet names (no "honey", "love", "sis", "girl", "sweetie", etc.). Speak like a caring, down-to-earth big sister.
- NEVER repeat the same validation phrase or sentence structure across responses. Vary your language every single time.
- You have TWO response modes the user can choose:
  • "Quick response" = Keep it SHORT and fast: 40–90 words maximum. Start with fresh validation, add 1–2 gentle supportive notes or tiny actionable ideas, then a short invitation to continue.
  • "Let me think on it" (deep mode) = Give a richer, more thoughtful reply. Acknowledge the user's choice ("You asked me to think on this with you…"). For questions about relief or medications (bloating, cramps, mood, etc.), you may mention common, generally safe OTC options or supplements that many women find helpful (e.g. ibuprofen for cramps/bloating, magnesium or vitamin B6 for mood/bloating, ginger tea, warm compress, hydration, light walking). Always frame it as: "These are things some women find helpful, but you should discuss with your doctor or healthcare provider first to make sure it's safe for you."
- At the VERY END of EVERY response (unless it's a true crisis redirection), add this exact line on its own new line:
"This is not a substitute for professional medical advice. Please consult your doctor or a mental health professional."

Stay grounded, real, and hopeful. Your goal is to make the user feel less alone.`;

// ============================================================================
// RESPONSE GENERATORS
// ============================================================================

async function generateLocalResponse(userMessage, ragEntry) {
  const isCrisis = CRISIS_CATEGORIES.has(ragEntry.category);

  // Crisis responses are never adapted — always return verbatim
  if (isCrisis) {
    return {
      mainContent: ragEntry.response,
      disclaimer: "This is not a substitute for professional medical advice. Please consult your doctor or a mental health professional.",
      source: 'rag',
      suggestedActions: [],
      flags: { escalate: true, crisis: true },
      route: 'tier_1_crisis',
      modelUsed: 'rag_verbatim'
    };
  }

  // Adapt the curated response to the user's message via Grok
  const grokApiKey = Deno.env.get('XAI_API_KEY');
  if (grokApiKey) {
    const adaptPrompt = `You are Luna 🌙. Adapt the following curated response to sound warm, empathetic, and sister-like.

Original Curated Response:
${ragEntry.response}

User Message: ${userMessage}

Guidelines:
- Keep the core advice from the curated response
- Make it feel personal and supportive
- Use natural, conversational language
- Do not add new medical advice
- Do NOT append any disclaimer — it is handled separately
- NEVER use pet names or terms of endearment such as "love", "honey", "sweetie", "darling", "dear" — address the user directly without any pet names

Respond with only the adapted message text, nothing else.`;

    try {
      const grokResponse = await fetch('https://api.x.ai/v1/chat/completions', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json', 'Authorization': `Bearer ${grokApiKey}` },
        body: JSON.stringify({
          model: 'grok-3-mini',
          messages: [{ role: 'user', content: adaptPrompt }],
          temperature: 0.65,
          max_tokens: 512
        })
      });

      if (grokResponse.ok) {
        const data = await grokResponse.json();
        // Strip any disclaimer the model may have appended
        let adapted = data.choices[0].message.content.trim();
        adapted = adapted.replace(/This is not a substitute for professional medical advice\..*$/s, '').trim();
        return {
          mainContent: adapted,
          disclaimer: "This is not a substitute for professional medical advice. Please consult your doctor or a mental health professional.",
          source: 'rag',
          suggestedActions: [],
          flags: { escalate: false, crisis: false },
          route: 'tier_2_rag_adapted',
          modelUsed: 'grok-3-mini'
        };
      }
    } catch (_) {
      // fall through to verbatim
    }
  }

  // Fallback: return verbatim curated response
  return {
    mainContent: ragEntry.response,
    disclaimer: "This is not a substitute for professional medical advice. Please consult your doctor or a mental health professional.",
    source: 'rag',
    suggestedActions: [],
    flags: { escalate: false, crisis: false },
    route: 'tier_2_rag_verbatim',
    modelUsed: 'rag_verbatim'
  };
}

async function generateGrokResponse(messages, contextInfo, ragResults, deepMode = false) {
  const grokApiKey = Deno.env.get('XAI_API_KEY');
  console.log('[LUNA] grok key present:', !!grokApiKey, 'key prefix:', grokApiKey?.slice(0,8));

  if (!grokApiKey) {
    return {
      mainContent: "I hear you and I'm here to listen. You matter and your feelings matter.",
      disclaimer: "This is not a substitute for professional medical advice. Please consult your doctor or a mental health professional.",
      source: 'rag',
      suggestedActions: [],
      flags: { escalate: false, crisis: false },
      route: 'local_fallback',
      modelUsed: 'none'
    };
  }

  const systemContent = LUNA_SYSTEM_PROMPT + '\n\n' + contextInfo;

  // Inject RAG context into the last user message
  const messagesWithContext = messages.map((m, i) => {
    if (i === messages.length - 1 && m.role === 'user' && ragResults.bestMatch) {
      return {
        role: 'user',
        content: `Context from curated responses:\n${ragResults.bestMatch.response}\n\nUser message: ${m.content}`
      };
    }
    return { role: m.role, content: m.content };
  });

  const grokResponse = await fetch('https://api.x.ai/v1/chat/completions', {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'Authorization': `Bearer ${grokApiKey}`
    },
    body: JSON.stringify({
      model: 'grok-3-mini',
      messages: [
        { role: 'system', content: systemContent + `\n\nCURRENT MODE: ${deepMode ? 'DEEP — give a richer, more thoughtful reply. Start with "You asked me to think on this with you…"' : 'QUICK — keep mainContent to 40–90 words maximum. Be warm but brief.'}\n\nIMPORTANT: Respond ONLY with a valid JSON object with keys: mainContent (string — your response, no disclaimer), suggestedActions (array of strings), flags (object with escalate and crisis booleans).` },
        ...messagesWithContext
      ],
      response_format: { type: 'json_object' },
      temperature: deepMode ? 0.75 : 0.7,
      max_tokens: deepMode ? 900 : 400
    })
  });

  if (!grokResponse.ok) {
    const errBody = await grokResponse.text();
    console.error('[LUNA] grok error body:', errBody);
    throw new Error(`Grok API error: ${grokResponse.status} ${grokResponse.statusText} — ${errBody}`);
  }

  const grokData = await grokResponse.json();
  const content = grokData.choices[0].message.content;

  try {
    const parsed = JSON.parse(content);
    // Normalize: extract mainContent from `message` if model used old key
    const mainContent = parsed.mainContent || parsed.message || '';
    // Strip any disclaimer the model may have appended to the content
    const cleanContent = mainContent.replace(/This is not a substitute for professional medical advice\..*$/s, '').trim();
    return {
      ...parsed,
      mainContent: cleanContent,
      disclaimer: "This is not a substitute for professional medical advice. Please consult your doctor or a mental health professional.",
      source: 'grok',
      route: 'tier_3_grok',
      modelUsed: 'grok-3-mini'
    };
  } catch {
    return {
      mainContent: content.replace(/This is not a substitute for professional medical advice\..*$/s, '').trim(),
      disclaimer: "This is not a substitute for professional medical advice. Please consult your doctor or a mental health professional.",
      source: 'grok',
      suggestedActions: [],
      flags: { escalate: false, crisis: false },
      route: 'tier_3_grok',
      modelUsed: 'grok-3-mini'
    };
  }
}

